        .byte $04, $1E, $08   ; row 02
        .byte $0C, $3F, $0C   ; row 03
        .byte $3C, $3F, $0F   ; row 04
        .byte $7C, $7F, $0F   ; row 05
        .byte $7C, $7F, $0F   ; row 06
        .byte $78, $7F, $07   ; row 07
        .byte $78, $7F, $07   ; row 08
        .byte $78, $7F, $07   ; row 09
        .byte $70, $7F, $03   ; row 10
        .byte $70, $7F, $03   ; row 11
        .byte $78, $7F, $07   ; row 12
        .byte $78, $7F, $07   ; row 13
        .byte $78, $7F, $07   ; row 14
        .byte $60, $7F, $01   ; row 15

; bishop
chess_bishop_mask:
