        .byte $00, $1E, $00   ; row 01
        .byte $00, $0C, $00   ; row 02
        .byte $00, $1E, $00   ; row 03
        .byte $00, $3F, $00   ; row 04
        .byte $40, $7F, $00   ; row 05
        .byte $60, $7F, $01   ; row 06
