        .byte $40, $7F, $00   ; row 11
        .byte $00, $3F, $00   ; row 12
        .byte $40, $7F, $00   ; row 13
        .byte $60, $7F, $01   ; row 14
        .byte $60, $7F, $01   ; row 15

; knight
chess_knight_mask:
